<?php// delete_cart_item.phpsession_start();// Variablesif(is_numeric($_GET['item'])){	$item = $_GET['item'];}else{	exit ("Pfff... rot op!");}// Wederom, kijken of winkelwagen bestaatif (empty($_SESSION['cart'])){	// Geen winkelwagen? Uitzetbeleid! :)		header("Location: index.php");		} else {	// Winkelwagen uit elkaar plukken	$cart = explode("|",$_SESSION['cart']);	// Tellen (eenzijdig hè?)	$count = count($cart);	// kijken of het in de winkelwagen staat	foreach($cart as $products) {		// Split		/*			$product[x] -->				 x == 0 -> productnummer				 x == 1 -> hoeveelheid		*/		$product = explode(",",$products);		$i++;		if ($i != $item) {	// Dus als die niet die is die verwijderd moet worden			// Var toevoegen aan nieuwe winkelwagen			$inNewCart = $product[0].",".$product[1];			$newCart = $newCart."|".$inNewCart;		}	}		// Luiheid, blijheid... er staat nog een | vooraan, even weghalen (had natuurlijk ook eerder	// een controle kunnen doen en die daar niet plaatsen.. :)	$newCart = substr($newCart,1);}// Verwijder de 'oude' winkelwagen en bouw een nieuwesession_unset($_SESSION['cart']);$_SESSION['cart'] = $newCart;// En terugsturenheader("Location: cart.php");?>